from flask import Flask, request, jsonify
import os

app = Flask(__name__)

# Directory to store annotations
ANNOTATIONS_DIR = 'annotations'
if not os.path.exists(ANNOTATIONS_DIR):
    os.makedirs(ANNOTATIONS_DIR)

# In-memory storage for annotations
labels_storage = {}

@app.route('/annotate', methods=['POST'])
def annotate():
    data = request.json
    image_id = data.get('image_id')
    label = data.get('label')
    
    if not image_id or not label:
        return jsonify({'error': 'Invalid data'}), 400
    
    if image_id not in labels_storage:
        labels_storage[image_id] = []
    
    labels_storage[image_id].append(label)
    with open(os.path.join(ANNOTATIONS_DIR, f'{image_id}.txt'), 'a') as f:
        f.write(f"{label}\n")
    
    return jsonify({'message': 'Label received'}), 200

@app.route('/aggregate', methods=['GET'])
def aggregate():
    aggregated_labels = {}
    for image_id, labels in labels_storage.items():
        if labels:
            majority_label = max(set(labels), key=labels.count)
            aggregated_labels[image_id] = majority_label
    
    return jsonify(aggregated_labels), 200

# Example function to train a model (dummy implementation)
def train_model(data):
    # Placeholder for training logic
    print("Training model with data:", data)

@app.route('/train', methods=['POST'])
def train():
    aggregated_labels = {}
    for image_id, labels in labels_storage.items():
        if labels:
            majority_label = max(set(labels), key=labels.count)
            aggregated_labels[image_id] = majority_label
    
    # Dummy training data
    training_data = [{'image': image_id, 'label': label} for image_id, label in aggregated_labels.items()]
    
    train_model(training_data)
    
    return jsonify({'message': 'Model trained'}), 200

if __name__ == '__main__':
    app.run(debug=True)